const input = $input.first().json.fields.Seniority;

// If already an array, return properly formatted array
if (Array.isArray(input)) {
  return [
    {
      json: {
        output: JSON.stringify(input)
      }
    }
  ];
}

// If it's a string like "[founder, ceo]"
const cleaned = input
  .replace(/^\[|\]$/g, '')
  .split(',')
  .map(item => item.trim());

return [
  {
    json: {
      output: JSON.stringify(cleaned)
    }
  }
];

const text = $input.all()
  .map(item => `
Prospect ID: ${item.json["prospect-id"] || ""}
Company Name: ${item.json["Company Name"] || ""}
Company Industry: ${item.json["Company Name"] || ""}
Company Description: ${item.json["Company Description"] || ""}
Prospect Name: ${item.json["first name"] || ""}
`)
  .join("\n-------------------\n");

return [
  {
    json: {
      prospects_text: text
    }
  }
];
